// src/main/java/com/example/sociallogin/auth/TokenExchangeService.kt
package com.example.sociallogin.auth

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.FormBody
import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONObject

/**
 * OAuth token exchange MUST happen server-side.
 * This client sends the auth code to YOUR backend, which holds the client secrets securely.
 * 
 * IMPORTANT: Client secrets (Facebook App Secret, Google Client Secret) are stored
 * ONLY on the backend server, never in the mobile app.
 */
object TokenExchangeService {

    // Your backend server endpoint that holds the secrets and performs token exchange
    private const val BACKEND_BASE_URL = "https://your-api-server.com/auth"

    private val client = OkHttpClient()

    /**
     * Sends the authorization code to your backend server.
     * The backend server (which securely holds the client secrets) exchanges it for tokens.
     */
    suspend fun exchangeCodeViaBackend(
        provider: String,
        authCode: String
    ): TokenResponse = withContext(Dispatchers.IO) {
        val requestBody = FormBody.Builder()
            .add("provider", provider)
            .add("code", authCode)
            .build()

        val request = Request.Builder()
            .url("$BACKEND_BASE_URL/exchange-token")
            .post(requestBody)
            .build()

        val response = client.newCall(request).execute()
        val body = response.body?.string() ?: throw Exception("Empty response from server")

        if (!response.isSuccessful) {
            throw Exception("Token exchange failed: ${response.code} - $body")
        }

        val json = JSONObject(body)
        TokenResponse(
            accessToken = json.getString("access_token"),
            refreshToken = json.optString("refresh_token"),
            expiresIn = json.optLong("expires_in", 3600),
            userId = json.optString("user_id"),
            email = json.optString("email"),
            displayName = json.optString("display_name")
        )
    }

    /**
     * For providers that give us an access token directly (like Facebook Login SDK),
     * we validate the token server-side.
     */
    suspend fun validateTokenViaBackend(
        provider: String,
        accessToken: String
    ): TokenResponse = withContext(Dispatchers.IO) {
        val requestBody = FormBody.Builder()
            .add("provider", provider)
            .add("access_token", accessToken)
            .build()

        val request = Request.Builder()
            .url("$BACKEND_BASE_URL/validate-token")
            .post(requestBody)
            .build()

        val response = client.newCall(request).execute()
        val body = response.body?.string() ?: throw Exception("Empty response from server")

        if (!response.isSuccessful) {
            throw Exception("Token validation failed: ${response.code} - $body")
        }

        val json = JSONObject(body)
        TokenResponse(
            accessToken = json.getString("access_token"),
            refreshToken = json.optString("refresh_token"),
            expiresIn = json.optLong("expires_in", 3600),
            userId = json.optString("user_id"),
            email = json.optString("email"),
            displayName = json.optString("display_name")
        )
    }

    data class TokenResponse(
        val accessToken: String,
        val refreshToken: String?,
        val expiresIn: Long,
        val userId: String?,
        val email: String?,
        val displayName: String?
    )
}

// src/main/java/com/example/sociallogin/auth/FacebookAuthProvider.kt
package com.example.sociallogin.auth

import android.content.Intent
import androidx.activity.ComponentActivity
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult

class FacebookAuthProvider(
    private val activity: ComponentActivity,
    private val callback: SocialAuthCallback
) {
    private val callbackManager = CallbackManager.Factory.create()

    init {
        LoginManager.getInstance().registerCallback(
            callbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onCancel() {
                    callback.onAuthResult(AuthResult.Cancelled)
                }

                override fun onError(error: FacebookException) {
                    callback.onAuthResult(
                        AuthResult.Error("Facebook login failed: ${error.message}", error)
                    )
                }

                override fun onSuccess(result: LoginResult) {
                    val token = result.accessToken
                    // Send the access token to our backend for validation
                    // The backend (not the client) uses the Facebook App Secret to verify it
                    callback.onAuthResult(
                        AuthResult.Success(
                            provider = "facebook",
                            userId = token.userId,
                            displayName = null, // Fetch from Graph API if needed
                            email = null,
                            accessToken = token.token
                        )
                    )
                }
            }
        )
    }

    fun signIn() {
        LoginManager.getInstance().logInWithReadPermissions(
            activity,
            callbackManager,
            listOf("email", "public_profile")
        )
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
    }

    fun signOut() {
        LoginManager.getInstance().logOut()
    }
}

// src/main/java/com/example/sociallogin/auth/GoogleAuthProvider.kt
package com.example.sociallogin.auth

import android.content.Intent
import android.content.IntentSender
import androidx.activity.ComponentActivity
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.IntentSenderRequest
import androidx.activity.result.contract.ActivityResultContracts
import com.example.sociallogin.BuildConfig
import com.google.android.gms.auth.api.identity.BeginSignInRequest
import com.google.android.gms.auth.api.identity.Identity
import com.google.android.gms.auth.api.identity.SignInClient
import com.google.android.gms.common.api.ApiException

class GoogleAuthProvider(
    private val activity: ComponentActivity,
    private val callback: SocialAuthCallback
) {
    private val oneTapClient: SignInClient = Identity.getSignInClient(activity)

    // Only the CLIENT ID is needed on the mobile client - this is semi-public by design
    // The CLIENT SECRET stays on your backend server
    private val signInRequest = BeginSignInRequest.builder()
        .setGoogleIdTokenRequestOptions(
            BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                .setSupported(true)
                .setServerClientId(BuildConfig.GOOGLE_CLIENT_ID)
                .setFilterByAuthorizedAccounts(false)
                .build()
        )
        .setAutoSelectEnabled(true)
        .build()

    private val signInLauncher: ActivityResultLauncher<IntentSenderRequest> =
        activity.registerForActivityResult(
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result ->
            try {
                val credential = oneTapClient.getSignInCredentialFromIntent(result.data)
                val idToken = credential.googleIdToken

                if (idToken != null) {
                    // Send the ID token to your backend for verification
                    // The backend verifies the token using Google's public keys
                    // and uses the CLIENT SECRET only if exchanging for a refresh token
                    callback.onAuthResult(
                        AuthResult.Success(
                            provider = "google",
                            userId = credential.id,
                            displayName = credential.displayName,
                            email = credential.id,
                            accessToken = idToken
                        )
                    )
                } else {
                    callback.onAuthResult(
                        AuthResult.Error("No ID token received from Google")
                    )
                }
            } catch (e: ApiException) {
                callback.onAuthResult(
                    AuthResult.Error("Google sign-in failed: ${e.message}", e)
                )
            }
        }

    fun signIn() {
        oneTapClient.beginSignIn(signInRequest)
            .addOnSuccessListener(activity) { result ->
                try {
                    val intentSenderRequest = IntentSenderRequest.Builder(
                        result.pendingIntent.intentSender
                    ).build()
                    signInLauncher.launch(intentSenderRequest)
                } catch (e: IntentSender.SendIntentException) {
                    callback.onAuthResult(
                        AuthResult.Error("Google sign-in intent failed: ${e.message}", e)
                    )
                }
            }
            .addOnFailureListener(activity) { e ->
                callback.onAuthResult(
                    AuthResult.Error("Google sign-in failed: ${e.message}", e)
                )
            }
    }

    fun signOut() {
        oneTapClient.signOut()
    }
}

// src/main/java/com/example/sociallogin/auth/SocialLoginManager.kt
package com.example.sociallogin.auth

import android.content.Intent
import androidx.activity.ComponentActivity
import androidx.lifecycle.lifecycleScope
import kotlinx.coroutines.launch

class SocialLoginManager(
    private val activity: ComponentActivity,
    private val onResult: (AuthResult) -> Unit
) : SocialAuthCallback {

    private val facebookAuth = FacebookAuthProvider(activity, this)
    private val googleAuth = GoogleAuthProvider(activity, this)

    override fun onAuthResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                // Forward the token to our backend for secure validation/exchange
                activity.lifecycleScope.launch {
                    try {
                        val backendResponse = TokenExchangeService.validateTokenViaBackend(
                            provider = result.provider,
                            accessToken = result.accessToken
                        )
                        onResult(
                            AuthResult.Success(
                                provider = result.provider,
                                userId = backendResponse.userId ?: result.userId,
                                displayName = backendResponse.displayName ?: result.displayName,
                                email = backendResponse.email ?: result.email,
                                accessToken = backendResponse.accessToken
                            )
                        )
                    } catch (e: Exception) {
                        onResult(AuthResult.Error("Backend validation failed: ${e.message}", e))
                    }
                }
            }
            else -> onResult(result)
        }
    }

    fun signInWithFacebook() = facebookAuth.signIn()
    fun signInWithGoogle() = googleAuth.signIn()

    fun signOut() {
        facebookAuth.signOut()
        googleAuth.signOut()
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookAuth.handleActivityResult(requestCode, resultCode, data)
    }
}

// src/main/java/com/example/sociallogin/LoginActivity.kt
package com.example.sociallogin

import android.content.Intent
import android.os.Bundle
import android.util.Log
import android.widget.Button
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import com.example.sociallogin.auth.AuthResult
import com.example.sociallogin.auth.SocialLoginManager

class LoginActivity : AppCompatActivity() {

    private lateinit var socialLoginManager: SocialLoginManager
    private lateinit var statusText: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        statusText = findViewById(R.id.statusText)

        socialLoginManager = SocialLoginManager(this) { result ->
            runOnUiThread {
                when (result) {
                    is AuthResult.Success -> {
                        statusText.text = "Signed in as: ${result.displayName ?: result.email ?: result.userId}"
                        Log.i("LoginActivity", "Auth success via ${result.provider}")
                    }
                    is AuthResult.Error -> {
                        statusText.text = "Error: ${result.message}"
                        Toast.makeText(this, result.message, Toast.LENGTH_LONG).show()
                        Log.e("LoginActivity", "Auth error", result.exception)
                    }
                    is AuthResult.Cancelled -> {
                        statusText.text = "Sign-in cancelled"
                    }
                }
            }
        }

        findViewById<Button>(R.id.btnFacebookLogin).setOnClickListener {
            socialLoginManager.signInWithFacebook()
        }

        findViewById<Button>(R.id.btnGoogleLogin).setOnClickListener {
            socialLoginManager.signInWithGoogle()
        }

        findViewById<Button>(R.id.btnSignOut).setOnClickListener {
            socialLoginManager.signOut()
            statusText.text = "Signed out"
        }
    }

    @Deprecated("Deprecated in Java")
    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        super.onActivityResult(requestCode, resultCode, data)
        socialLoginManager.handleActivityResult(requestCode, resultCode, data)
    }
}

